#include <stdio.h>
#include <stdlib.h>

typedef struct {int x; int y;} Cell;

int cmp(const void *a, const void *b) {
    Cell *c1 = (Cell *)a, *c2 = (Cell *)b;
    if (c1->x != c2->x) return c1->x - c2->x;
    return c1->y - c2->y;
}

int lower_bound(int *arr, int size, int val) {
    int l = 0, r = size; // [l, r)
    while (l < r) {
        int m = (l + r) >> 1;
        if (arr[m] >= val) r = m; else l = m + 1;
    }
    return l;
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        long long N, M; int K; scanf("%lld %lld %d", &N, &M, &K);
        Cell *tmp = (Cell *)malloc(sizeof(Cell) * K);
        int cnt = 0;
        for (int i = 0; i < K; ++i) {
            int x, y; scanf("%d %d", &x, &y);
            if ((long long)x < N && (long long)y < M) {
                tmp[cnt].x = x; tmp[cnt].y = y; ++cnt;
            }
        }
        qsort(tmp, cnt, sizeof(Cell), cmp);
        int *dp = (int *)malloc(sizeof(int) * cnt);
        int len = 0;
        for (int i = 0; i < cnt; ++i) {
            int pos = lower_bound(dp, len, tmp[i].y);
            if (pos == len) dp[len++] = tmp[i].y; else dp[pos] = tmp[i].y;
        }
        long long ans = (N - 1) + (M - 1) - len;
        printf("%lld\n", ans);
        free(tmp);
        free(dp);
    }
    return 0;
}

