    while(T--){
        long long N,M; int K; cin>>N>>M>>K;
        vector<pair<int,int>> v; v.reserve(K);
        for(int i=0;i<K;++i){
            int x,y;cin>>x>>y;
            if((long long)x<N && (long long)y<M) v.emplace_back(x,y);
        }
        sort(v.begin(), v.end(), [](auto &a, auto &b){
            if(a.first!=b.first) return a.first<b.first;
            return a.second<b.second;
        });
        vector<int> dp;
        for(auto &p: v){
            int y=p.second;
            auto it=lower_bound(dp.begin(), dp.end(), y);
            if(it==dp.end()) dp.push_back(y);
            else *it=y;
        }
        long long ans = (N-1)+(M-1)- (long long)dp.size();
        cout<<ans<<"\n";
    }
    return 0;
}

