const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/).map(Number);
let idx = 0;
const T = input[idx++];
let out = [];
for (let tc = 0; tc < T; ++tc) {
  const N = input[idx++];
  const M = input[idx++];
  const K = input[idx++];
  let specials = [];
  for (let i = 0; i < K; ++i) {
    const x = input[idx++];
    const y = input[idx++];
    if (x < N && y < M) specials.push([x, y]);
  }
  specials.sort((a, b) => a[0] === b[0] ? a[1] - b[1] : a[0] - b[0]);
  const dp = [];
  for (const [, y] of specials) {
    // binary search lower_bound
    let l = 0, r = dp.length;
    while (l < r) {
      const m = (l + r) >> 1;
      if (dp[m] >= y) r = m; else l = m + 1;
    }
    if (l === dp.length) dp.push(y); else dp[l] = y;
  }
  const ans = (N - 1) + (M - 1) - dp.length;
  out.push(String(ans));
}
console.log(out.join('\n'));
